[Form]
public class FWFTextBlockGroupAssignment extends FormRun
{
    FWFTextBlockModule	module;
    Common				callerTable;
    str 20				refId;


}

/// <summary>
///
/// </summary>
public void init()
{
    super();

    if (element.args().parmEnumType() == enumNum(FWFTextBlockModule))
    {
        module = element.args().parmEnum();
    }

    switch (module)
    {
        case FWFTextBlockModule::Customer:
            element.design().caption("@FWFTextBlock:CustTextBlockGroupAssign");
            break;

        case FWFTextBlockModule::Supplier:
            element.design().caption("@FWFTextBlock:VendTextBlockGroupAssign");
            break;

        case FWFTextBlockModule::ReleasedProduct:
            element.design().caption("@FWFTextBlock:ProdTextBlockGroupAssign");
            break;

        case FWFTextBlockModule::Project:
            element.design().caption("@FWFTextBlock:ProjTextBlockGroupAssign");
            break;
    }

    if (element.args() && element.args().record())
    {
        callerTable = element.args().record();
    }

    switch(callerTable.TableId)
    {
        case tableNum(CustTable) :
            CustTable	custTable = callerTable as CustTable;
            refId = custTable.AccountNum;
            break;

        case tableNum(VendTable) :
            VendTable	vendTable = callerTable as VendTable;
            refId = vendTable.AccountNum;
            break;

        case tableNum(InventTable)  :
            InventTable inventTable = callerTable as InventTable;
            refId = inventTable.ItemId;
            break;

        case tableNum(ProjTable)  :
            ProjTable projTable = callerTable as ProjTable;
            refId = projTable.ProjId;
            break;
    }

    FWFTextBlockGroupAssign_ds.query().dataSourceTable(tableNum(FWFTextBlockGroupAssign)).clearRanges();
    FWFTextBlockGroupAssign_ds.query().dataSourceTable(tableNum(FWFTextBlockGroupAssign)).clearDynalinks();
    FWFTextBlockGroupAssign_ds.query().dataSourceTable(tableNum(FWFTextBlockGroupAssign)).addRange(fieldNum(FWFTextBlockGroupAssign, Module)).value(queryValue(module));
    FWFTextBlockGroupAssign_ds.query().dataSourceTable(tableNum(FWFTextBlockGroupAssign)).addRange(fieldNum(FWFTextBlockGroupAssign, RefId)).value(queryValue(refId));

}

/// <summary>
///
/// </summary>
/// <param name = "_formControl"></param>
/// <param name = "_filterStr"></param>
public void lookup(FormControl _formControl, str _filterStr)
{
    FWFTextBlockGroup::lookup(_formControl, module);
}
